    fun createSystemView(createSystemViewRequest: CreateSystemViewRequest) : GetViewsForBankAccount200ResponseViewsInner {
        val localVarResponse = createSystemViewWithHttpInfo(createSystemViewRequest = createSystemViewRequest)

        return when (localVarResponse.responseType) {
